import React from "react";
import { motion } from "framer-motion";
import { Shield, Zap, Heart } from "lucide-react";

export function HeroSection() {
  const features = [
    { icon: <Zap className="w-4 h-4" />, text: "Instant Pickups" },
    { icon: <Shield className="w-4 h-4" />, text: "Verified NGOs" },
    { icon: <Heart className="w-4 h-4" />, text: "Social Impact" },
  ];

  return (
    <div className="flex-1 flex flex-col justify-center px-6 lg:px-12 py-12 lg:py-0 max-w-3xl">
      <motion.div
        initial={{ opacity: 0, x: -20 }}
        animate={{ opacity: 1, x: 0 }}
        transition={{ delay: 0.2 }}
      >
        <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-primary/10 border border-primary/20 text-primary-light text-xs font-bold mb-6">
          <span className="relative flex h-2 w-2">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-primary opacity-75"></span>
            <span className="relative inline-flex rounded-full h-2 w-2 bg-primary"></span>
          </span>
          V1.0 LIVE NOW
        </div>

        <h1 className="text-5xl lg:text-7xl font-extrabold leading-tight mb-6">
          Rescue Food, <br />
          <span className="text-transparent bg-clip-text bg-gradient-to-r from-primary to-secondary">
            Change Lives.
          </span>
        </h1>

        <p className="text-lg text-white/60 mb-10 max-w-xl leading-relaxed">
          The enterprise-grade platform connecting restaurants, hostels, and donors directly to local NGOs. Minimize waste, maximize impact.
        </p>

        <div className="flex flex-wrap gap-4 mb-12">
          {features.map((f, i) => (
            <div key={i} className="flex items-center gap-2 px-4 py-2 bg-white/5 border border-white/10 rounded-xl text-sm font-medium text-white/80">
              <span className="text-primary">{f.icon}</span>
              {f.text}
            </div>
          ))}
        </div>

        <div className="flex items-center gap-6">
          <div className="flex -space-x-3">
            {[1, 2, 3, 4].map((i) => (
              <div key={i} className="w-10 h-10 rounded-full border-2 border-[#0f172a] bg-white/10 flex items-center justify-center text-[10px] overflow-hidden">
                <img src={`https://i.pravatar.cc/40?img=${i+10}`} alt="User" />
              </div>
            ))}
          </div>
          <p className="text-sm text-white/40 font-medium">
            Joined by <span className="text-white">500+</span> organizations
          </p>
        </div>
      </motion.div>
    </div>
  );
}
